    starts?: string | null;
  };
};

type UseUpdateCommitmentProps = MutationProps<
  ActionPagesCommitmentShowResponse,
  UpdateCommitmentRequest
>;

export const useUpdateCommitment = ({
  onError,
  onSuccess,
}: UseUpdateCommitmentProps = {}) => {
  const queryClient = useQueryClient();

  return useMutation<
    ActionPagesCommitmentShowResponse,
    ApiErrorType,
    UpdateCommitmentRequest
  >({
    mutationFn: async (data: UpdateCommitmentRequest) => {
      const { id, accountId, ...updateData } = data;

      return getApiClient().put<ActionPagesCommitmentShowResponse>(
        `/action_pages_commitments/${id}`,
        {
          ...updateData,
          accountId,
        },
      );
