    onError: (error) => {
      onError?.(error);
    },
    onSuccess: (data, variables) => {
      // Invalidate commitment queries
      queryClient.invalidateQueries({
        queryKey: commitmentQueryKeys.entity({
          parameters: { accountId: variables.accountId },
        }).queryKey,
      });

      queryClient.invalidateQueries({
        queryKey: commitmentQueryKeys.list({
          parameters: { accountId: variables.accountId },
        }).queryKey,
      });

      onSuccess?.(data, variables);
    },
  });
};

